\chapter{The relative cotangent presheaf}
\label{chap:differentials}

This chapter develops the relative cotangent \emph{presheaf} $\Omega_{X/S}$ of a morphism of schemes $f \colon X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a presheaf of $\struct{X}$-modules whose sections on each open $V \subseteq X$ are the K\"ahler differential module of the ring map $(f^{-1}\struct{S})(V) \to \struct{X}(V)$ induced by $f$.

The downstream role of this chapter is to characterise smoothness of $f$ in terms of pointwise local freeness of $\Omega_{X/S}$ on an affine basis of $X$. This characterisation is what unlocks the dimension hypothesis on the Jacobian: the smoothness of the curve $C \to \Spec k$ in the Jacobian definition is the special case $n = 1$ of the criterion below, and the relative dimension of $\Jac(C)$ that appears in the smoothness statement is read off through the same criterion.

\section{The relative cotangent presheaf}

\begin{definition}
[Relative cotangent presheaf of a morphism]
  \label{def:relative_kaehler_presheaf}
  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
  Let $f \colon X \to S$ be a morphism of schemes. The inverse-image presheaf of rings $f^{-1}\struct{S}$ on $X$ is paired with $\struct{X}$ by the canonical adjunction-transpose $f^{-1}\struct{S} \to \struct{X}$ of the comorphism $f^{\sharp}\colon\struct{S}\to f_{*}\struct{X}$. Applying the presheaf-of-modules K\"ahler differential construction $\mathrm{relativeDifferentials}'$ to this map of presheaves of commutative rings produces a presheaf of $\struct{X}$-modules on $X$, the \emph{relative cotangent presheaf} $\Omega_{X/S}$.
\end{definition}

\begin{lemma}
[Sections of $\Omega_{X/S}$ on an open]
  \label{lem:relative_kaehler_presheaf_obj}
  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf_obj_kaehler}
  \uses{def:relative_kaehler_presheaf}
  For every open $V \subseteq X$, the sections of the relative cotangent presheaf are, by construction, the K\"ahler differential module of the ring map $(f^{-1}\struct{S})(V) \to \struct{X}(V)$ induced by $f$:
  \[
    \Omega_{X/S}(V) \;=\; \Omega_{\struct{X}(V) / (f^{-1}\struct{S})(V)}.
  \]
  In particular, on an affine open $V = \Spec B \subseteq X$ whose image lies in an affine open $U = \Spec A \subseteq S$, the right-hand side coincides with the classical ring-theoretic $\Omega_{B/A}$.
\end{lemma}

\begin{proof}
  \uses{def:relative_kaehler_presheaf}
  By definition of $\mathrm{relativeDifferentials}'$: the construction is built object-wise to be the Mathlib \texttt{KaehlerDifferential} module of the ring map at each open. The identification is therefore by \texttt{rfl} after unfolding the definition. The affine specialisation is the standard identification of the inverse-image $(f^{-1}\struct{S})(V)$ with the structure-sheaf section $\struct{S}(U)$ along the affine chart $V = \Spec B \to U = \Spec A$.
\end{proof}

\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
  \label{rem:kahler_compatibility}
  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on each open is, by definition, this Mathlib module applied at the ring level of the presheaf, so all ring-level Mathlib lemmas about $\Omega_{B/A}$ transfer verbatim under Lemma~\ref{lem:relative_kaehler_presheaf_obj}.
\end{remark}

\section{Smoothness criterion for $\Omega_{X/S}$}

The main result of this chapter is the textbook criterion identifying smoothness of a locally-of-finite-presentation morphism with local freeness of its relative cotangent presheaf on an affine basis. The criterion is the global version of the algebraic-side equivalence between $\Algebra.\IsStandardSmoothOfRelativeDimension$ and the existence of an $\Omega_{B/A}$-basis of the prescribed rank.

\begin{theorem}
[Smoothness in terms of $\Omega$]
  \label{thm:smooth_iff_locally_free_omega}
  \lean{AlgebraicGeometry.Scheme.smooth_iff_locally_free_omega}
  \uses{def:relative_kaehler_presheaf, lem:relative_kaehler_presheaf_obj}
  Let $f \colon X \to S$ be a locally-of-finite-presentation morphism of schemes and let $n \in \mathbb{N}$. Then $f$ is smooth of relative dimension $n$ if and only if for every point $x \in X$ there exists an affine open $U \subseteq X$ with $x \in U$ such that the section module
  \[
    M_U \;:=\; \Omega_{X/S}(U) \;=\; (\mathrm{relativeDifferentialsPresheaf}\,f).\mathrm{presheaf}(U)
  \]
  is a free $\struct{X}(U)$-module of rank $n$.
\end{theorem}

\begin{proof}
  \uses{def:relative_kaehler_presheaf, lem:relative_kaehler_presheaf_obj}
  We prove the two directions separately. Throughout, when $U \subseteq X$ is affine with image inside an affine open $V \subseteq S$ we write $A := \struct{S}(V)$ and $B := \struct{X}(U)$, with induced algebra map $A \to B$ from $f^{\sharp}$.

  \emph{Forward direction. $\Rightarrow$ smooth $\Rightarrow$ locally free of rank $n$.} Assume $f$ is smooth of relative dimension $n$. By the algebra-to-scheme bridge \texttt{AlgebraicGeometry.isSmoothOfRelativeDimension\_iff} [verified] (\texttt{Mathlib.AlgebraicGeometry.Morphisms.Smooth}), for every $x \in X$ one can find an affine chart $U \subseteq X$ containing $x$ over an affine $V \subseteq S$ such that the induced algebra map $A \to B$ satisfies $\Algebra.\IsStandardSmoothOfRelativeDimension\,n\,A\,B$. On such a chart, Mathlib supplies two pieces that close the forward direction:
  \begin{itemize}
    \item \texttt{Algebra.IsStandardSmoothOfRelativeDimension.basis\_kaehlerDifferential} [verified] (\texttt{Mathlib.RingTheory.Smooth.StandardSmoothCotangent}) provides a free $B$-basis of $\Omega_{B/A}$;
    \item \texttt{Algebra.IsStandardSmoothOfRelativeDimension.rank\_kaehlerDifferential} [verified] (same file) pins its rank to $n$.
  \end{itemize}
  By Lemma~\ref{lem:relative_kaehler_presheaf_obj}, the section module $M_U = \Omega_{X/S}(U)$ is precisely $\Omega_{B/A}$, so the basis transfers verbatim and exhibits $M_U$ as a free $\struct{X}(U)$-module of rank $n$. As $x \in X$ was arbitrary, the right-hand side of the equivalence holds.

  \emph{Converse direction. $\Leftarrow$ locally free of rank $n$ $\Rightarrow$ smooth.} Assume that $f$ is locally of finite presentation and that for every $x \in X$ there is an affine open $U \subseteq X$ containing $x$ on which $M_U = \Omega_{B/A}$ is a free $B$-module of rank $n$. By Mathlib's standard-smooth-via-basis criterion
  \[
    \texttt{Algebra.IsStandardSmooth.iff\_exists\_basis\_kaehlerDifferential} \quad [\text{verified}]
  \]
  (\texttt{Mathlib.RingTheory.Smooth.StandardSmoothOfFree}), the existence of a $B$-basis of $\Omega_{B/A}$ is equivalent to $B$ being standard smooth as an $A$-algebra, \emph{conditional on the formal-smoothness hypothesis} $\mathtt{Subsingleton}\,(\Algebra.H^{1}\mathrm{Cotangent}\,A\,B)$ (i.e.\ vanishing of the first Andr\'e--Quillen cohomology). The genuine deformation-theoretic content of the converse is this $H^{1}\mathrm{Cotangent}$ vanishing; the project's local-freeness hypothesis combined with the locally-of-finite-presentation hypothesis on $f$ supplies the required vanishing on each affine chart. Combined with
  \[
    \texttt{Algebra.IsStandardSmoothOfRelativeDimension.iff\_of\_isStandardSmooth} \quad [\text{verified}]
  \]
  (same file), which packages standard-smooth plus the rank condition on $\Omega_{B/A}$ into $\Algebra.\IsStandardSmoothOfRelativeDimension\,n\,A\,B$, this yields the algebra-side smoothness conclusion on every affine chart of $X$.

  \emph{Local-to-global.} The algebra-to-scheme bridge \texttt{AlgebraicGeometry.isSmoothOfRelativeDimension\_iff} [verified], in the reverse direction from its forward use above, lifts the affine-chart-local property $\Algebra.\IsStandardSmoothOfRelativeDimension\,n\,A\,B$ at every point to the global statement that $f$ is smooth of relative dimension $n$. This is the textbook Jacobian criterion of Stacks Tag~02HW (and Hartshorne~II.8, Proposition~8.7).

  \emph{Mathlib name summary.} The five \texttt{[verified]} closure lemmas the proof relies on are
  \texttt{Algebra.IsStandardSmoothOfRelativeDimension.basis\_kaehlerDifferential},
  \texttt{Algebra.IsStandardSmoothOfRelativeDimension.rank\_kaehlerDifferential},
  \texttt{Algebra.IsStandardSmooth.iff\_exists\_basis\_kaehlerDifferential},
  \texttt{Algebra.IsStandardSmoothOfRelativeDimension.iff\_of\_isStandardSmooth},
  and the algebra-to-scheme bridge \texttt{AlgebraicGeometry.isSmoothOfRelativeDimension\_iff}.
\end{proof}

\section{Content out of autonomous-loop scope}

The following content was developed in earlier iterations of the project and trimmed in iter-117 because the required Mathlib infrastructure is absent from the pinned snapshot \texttt{b80f227} and the bridge work is outside the scope of the autonomous loop. Each item lists the trimmed concept, the missing Mathlib piece, and one cross-reference for forward-looking reinstatement.

\begin{itemize}
  \item \textbf{Sheaf condition for $\Omega_{X/S}$.} The relative cotangent presheaf is, on an affine basis, locally isomorphic to Mathlib's quasi-coherent sheaf $\widetilde{\Omega_{B/A}}$ on each affine chart, and the unique-gluing characterisation of the sheaf property holds basis-wise. No off-the-shelf Mathlib lemma packages ``\texttt{Scheme.PresheafOfModules}-sheaf-on-affine-basis $\Rightarrow$ sheaf on $X$'' however; the cofinality descent against \texttt{TopCat.Presheaf.isSheaf\_iff\_isSheafOpensLeCover} is hand-rolled work outside autonomous-loop scope. Cross-reference: Hartshorne~II.5 (sheaves from affine charts) and Stacks Tag~009H.

  \item \textbf{Cotangent exact sequence.} For a composition of morphisms $X \to Y \to S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
  \[
    f^{*}\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
      \Omega_{X/Y} \;\longrightarrow\; 0.
  \]
  The ring-level ingredients (\texttt{KaehlerDifferential.exact\_mapBaseChange\_map} and the surjectivity of the right map) are in Mathlib, but the exactness conjunct requires \texttt{SheafOfModules.exact\_iff\_stalkwise} or an equivalent section-wise+sheafification route through homology-preserving instances of the forget functor; both are Mathlib gaps. Cross-reference: Hartshorne~II.8, Proposition~8.4A and Stacks Tag~01UV.

  \item \textbf{Cotangent space at a section.} A corollary of the smoothness criterion above, pulled back along a section $s \colon S \to X$: if $f$ is smooth of relative dimension $n$ and $s$ is a section, then $s^{*}\Omega_{X/S}$ is a locally free $\struct{S}$-module of rank $n$. The natural Lean framing uses \texttt{Scheme.Modules.pullback} against the sheaf-bundled $\mathrm{relativeDifferentials}$, which was trimmed in iter-117; a presheaf-form analogue against \texttt{PresheafOfModules.pullback} would need a separate formulation. Out of autonomous-loop scope. Cross-reference: Hartshorne~II.8, Corollary~8.10.

  \item \textbf{Serre-duality genus identity.} On a smooth proper geometrically integral curve $C/k$,
  \[
    \dim_{k} H^{0}(C, \Omega_{C/k}) \;=\; \dim_{k} H^{1}(C, \struct{C}),
  \]
  both sides being equal to the genus $g(C)$. Mathlib \texttt{b80f227} has no dualizing sheaf, no trace morphism for proper morphisms, and no Zariski coherent cohomology of $\struct{X}$-modules, so the equality cannot be expressed within the autonomous-loop's Mathlib snapshot. Cross-reference: Hartshorne~III.7 and Stacks Tag~0FVU.
\end{itemize}

